body:
compiling the following module gets this error : 
2nd expression of generate for-loop at test.v:52 is not constant!

module temp

#(parameter size=4, logsize=2)
(
  input  [logsize-1:0]    p_enc,  
  output  wire [size-1:0]    y
  );

  reg     [logsize-1:0] x;
  reg     [2**logsize -1:0] y1;
  integer pow2;
  reg     tmp;
  integer i;
  integer j;
  
  always@*
  begin
    x = p_enc;
    pow2 = 1;
    y1[0] = 0;
    
    for(i=0; i<logsize; i=i+1) begin
      for(j=0; j<pow2; j=j+1) begin /* line 52 with the error ( pow2 is constant but changes each i loop */
        tmp = y1[j];
        y1[j] = tmp | x[i];
        y1[j+pow2] = tmp & x[i];      
      end 
      pow2 = pow2+pow2;
    end
  end  
  assign y = y1[size-1:0];

endmodule
